### 2-3. 중복 조회 및 느린 JOIN

매칭 확정 후 통화 이력 저장 과정에서 이미 조회한 Entity를 재조회하는 패턴입니다.

**Before:**

```kotlin
@Transactional
fun confirmMatch(matchRequestId: String, targetUserId: String): CallEntity {
    val matchRequest = matchingRepository.findById(matchRequestId).orElseThrow()
    // 이미 matchRequest에서 userId를 알고 있음에도 재조회
    val requester = userRepository.findById(matchRequest.userId).orElseThrow()
    val target = userRepository.findById(targetUserId).orElseThrow()

    // 상태 업데이트
    matchingRepository.updateStatus(matchRequestId, MatchingStatus.MATCHED)
    matchingRepository.updateStatus(target.matchingId, MatchingStatus.MATCHED) // 별도 조회 발생

    return callRepository.save(
        CallEntity(
            requesterId = matchRequest.userId,
            targetId = targetUserId,
        )
    )
}
```

**After:**

```kotlin
@Transactional
fun confirmMatch(matchRequestId: String, targetMatchingId: String): CallEntity {
    // fetch join으로 한 번에 필요한 데이터 로드
    val (requesterMatching, targetMatching) = matchingRepository
        .findBothByIds(matchRequestId, targetMatchingId) // IN 쿼리 1번

    // Bulk update (개별 UPDATE 대신)
    matchingRepository.updateStatusBatch(
        ids = listOf(matchRequestId, targetMatchingId),
        status = MatchingStatus.MATCHED.value,
    )

    return callRepository.save(
        CallEntity(
            requesterId = requesterMatching.userId,
            targetId = targetMatching.userId,
        )
    )
}
```

