## 3. Redis 캐시 전략

### 3-1. 캐시 적용 지점 및 TTL 설계

| 캐시 키 | 적용 대상 | TTL | 무효화 시점 |
|---------|----------|-----|------------|
| `matching:pool:gender:{g}:age:{a}` | 성별/나이대별 대기자 풀 | 5초 | 매칭 큐 입장/이탈 시 |
| `user:preference:{userId}` | 사용자 매칭 선호도 | 10분 | 프로필 설정 변경 시 |
| `user:block-list:{userId}` | 차단 목록 | 5분 | 차단/해제 시 |
| `call:active:{userId}` | 현재 통화 중 여부 | 30분 | 통화 시작/종료 시 |
| `matching:stats:online` | 온라인 사용자 수 | 30초 | - |

### 3-2. 대기자 풀 캐시 구현

**Before (매 요청마다 DB 조회):**

```kotlin
@Service
class CallMatchingService(
    private val matchingRepository: CallMatchingRepository,
) {
    fun findMatchCandidates(gender: Int, ageGroup: Int): List<MatchCandidateDto> {
        // 매 요청마다 DB 쿼리 실행
        return matchingRepository.findWaitingByPreference(gender, ageGroup)
    }
}
```

**After (Redis 캐시 적용):**

```kotlin
// CacheConfig.kt
@Configuration
class CacheConfig {
    @Bean
    fun cacheManager(redisConnectionFactory: RedisConnectionFactory): CacheManager {
        val matchingPoolConfig = RedisCacheConfiguration.defaultCacheConfig()
            .entryTtl(Duration.ofSeconds(5)) // 매칭 풀은 5초 TTL
            .serializeValuesWith(
                RedisSerializationContext.SerializationPair.fromSerializer(
                    GenericJackson2JsonRedisSerializer()
                )
            )

        val userPreferenceConfig = RedisCacheConfiguration.defaultCacheConfig()
            .entryTtl(Duration.ofMinutes(10)) // 선호도는 10분 TTL

        return RedisCacheManager.builder(redisConnectionFactory)
            .withCacheConfiguration("matchingPool", matchingPoolConfig)
            .withCacheConfiguration("userPreference", userPreferenceConfig)
            .build()
    }
}
```

```kotlin
// CallMatchingService.kt
@Service
class CallMatchingService(
    private val matchingRepository: CallMatchingRepository,
    private val redisTemplate: RedisTemplate<String, Any>,
) {
    companion object {
        private const val MATCHING_POOL_KEY = "matching:pool:g%d:a%d"
        private const val POOL_TTL_SECONDS = 5L
    }

    @Cacheable(
        cacheNames = ["matchingPool"],
        key = "'g' + #gender + ':a' + #ageGroup",
    )
    @Transactional(readOnly = true)
    fun findMatchCandidates(gender: Int, ageGroup: Int): List<MatchCandidateDto> {
        return matchingRepository.findWaitingByPreference(gender, ageGroup)
    }

    @CacheEvict(
        cacheNames = ["matchingPool"],
        allEntries = true, // 풀 전체 무효화 (성별/나이 조합 다양)
    )
    @Transactional
    fun joinMatchingQueue(userId: String, preference: MatchingPreference): CallMatchingEntity {
        val entity = CallMatchingEntity(
            userId = userId,
            genderPref = preference.gender,
            agePref = preference.ageGroup,
            status = MatchingStatus.WAITING.value,
        )
        return matchingRepository.save(entity)
    }

    @CacheEvict(
        cacheNames = ["matchingPool"],
        allEntries = true,
    )
    @Transactional
    fun leaveMatchingQueue(matchingId: String) {
        matchingRepository.updateStatus(matchingId, MatchingStatus.CANCELLED.value)
    }
}
```

### 3-3. 차단 목록 캐시 (중요도 높음)

매칭마다 차단 여부 확인이 발생하므로 캐시 효과가 큽니다.

```kotlin
// BlockCacheService.kt
@Service
class BlockCacheService(
    private val blockRepository: BlockRepository,
    private val redisTemplate: RedisTemplate<String, String>,
) {
    companion object {
        private const val BLOCK_LIST_KEY = "user:block-list:%s"
        private val BLOCK_LIST_TTL = Duration.ofMinutes(5)
    }

    fun getBlockedUserIds(userId: String): Set<String> {
        val key = BLOCK_LIST_KEY.format(userId)
        val cached = redisTemplate.opsForSet().members(key)

        if (!cached.isNullOrEmpty()) return cached

        // Cache Miss: DB 조회 후 캐시 저장
        val blockedIds = blockRepository.findBlockedUserIdsByUserId(userId)
        if (blockedIds.isNotEmpty()) {
            redisTemplate.opsForSet().add(key, *blockedIds.toTypedArray())
            redisTemplate.expire(key, BLOCK_LIST_TTL)
        }
        return blockedIds.toSet()
    }

    fun invalidateBlockList(userId: String) {
        redisTemplate.delete(BLOCK_LIST_KEY.format(userId))
    }
}
```

### 3-4. 활성 통화 여부 Redis 관리

통화 중인 사용자를 Redis Set으로 관리하여 중복 매칭을 방지합니다.

```kotlin
// ActiveCallCacheService.kt
@Service
class ActiveCallCacheService(
    private val redisTemplate: RedisTemplate<String, String>,
) {
    companion object {
        private const val ACTIVE_CALL_KEY = "call:active:users" // Redis Set
        private val CALL_TTL = Duration.ofMinutes(30)
    }

    fun markAsInCall(userId: String) {
        redisTemplate.opsForSet().add(ACTIVE_CALL_KEY, userId)
        redisTemplate.expire(ACTIVE_CALL_KEY, CALL_TTL)
    }

    fun markAsAvailable(userId: String) {
        redisTemplate.opsForSet().remove(ACTIVE_CALL_KEY, userId)
    }

    fun isInCall(userId: String): Boolean {
        return redisTemplate.opsForSet().isMember(ACTIVE_CALL_KEY, userId) ?: false
    }

    // 매칭 후보 필터링 시 통화 중 사용자 한 번에 제거
    fun filterAvailableUsers(userIds: List<String>): List<String> {
        val inCallUsers = redisTemplate.opsForSet().members(ACTIVE_CALL_KEY) ?: emptySet()
        return userIds.filter { it !in inCallUsers }
    }
}
```

